#[allow(dead_code)]
#[path = "../protocol/mod.rs"]
mod protocol;

use anyhow::{Context, Result};
use std::{fs, path::PathBuf};
use ts_rs::TS;

fn main() -> Result<()> {
    let out = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("../src/lib/contracts/generated.ts");
    if let Some(parent) = out.parent() {
        fs::create_dir_all(parent).with_context(|| format!("create {}", parent.display()))?;
    }
    fs::write(out, bindings()).context("write generated TypeScript contracts")
}

fn bindings() -> String {
    let mut output = String::from(
        "// @generated by `cargo run --manifest-path app/src-tauri/Cargo.toml --bin export-bindings`\n",
    );
    output.push_str(
        "\nexport type JsonValue = null | boolean | number | string | JsonValue[] | { [key: string]: JsonValue };\n",
    );
    push::<protocol::Decision>(&mut output);
    push::<protocol::ClientScope>(&mut output);
    push::<protocol::ApprovalRequestBody>(&mut output);
    push::<protocol::Approval>(&mut output);
    push::<protocol::ApprovalDecisionBody>(&mut output);
    push::<protocol::ApprovalDecisionResponse>(&mut output);
    push::<protocol::RunEvent>(&mut output);
    push::<protocol::RunEventBody>(&mut output);
    push::<protocol::DesktopCommandBlock>(&mut output);
    push::<protocol::PtyOutputBody>(&mut output);
    push::<protocol::DesktopNamedRef>(&mut output);
    push::<protocol::DesktopSessionSnapshot>(&mut output);
    push::<protocol::DesktopSnapshotBody>(&mut output);
    push::<protocol::DesktopSessionLaunchBody>(&mut output);
    push::<protocol::DesktopRemoteSshBody>(&mut output);
    push::<protocol::DesktopWorktreeOpenBody>(&mut output);
    push::<protocol::CheckpointRecord>(&mut output);
    push::<protocol::CheckpointDiffFile>(&mut output);
    push::<protocol::CheckpointDiff>(&mut output);
    push::<protocol::CheckpointRestoreBody>(&mut output);
    push::<protocol::DesktopSessionInputBody>(&mut output);
    push::<protocol::DesktopPaneSplitBody>(&mut output);
    push::<protocol::DesktopCommandResponse>(&mut output);
    push::<protocol::PairRequest>(&mut output);
    push::<protocol::PairResponse>(&mut output);
    push::<protocol::ServerMessage>(&mut output);
    output
}

fn push<T: TS>(output: &mut String) {
    output.push('\n');
    output.push_str(
        &T::decl()
            .replacen("type ", "export type ", 1)
            .replace("bigint", "number"),
    );
    output.push('\n');
}
